import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_THEORETISCH_JAARWEDDE_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_THEORETISCH_JAARWEDDE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.FISCAAL_JAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.INDEXATOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONCODE_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKEN_CHAIN_FACTORY_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.RKM_COREHR_CONFIG_MANAGER;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.THEORETISCHE_JAARWEDDE_MODUS_KEY;

@Slf4j
public class BerekenTheoretischJaarWedde extends AbstractRekenCommand {

    private static final int STARTJAAR_NIEUWE_REDENERING_THEORETISCH_BELASTBAAR = 2007;
    private final ConstantManager constantManager;
    private final AardKodeExtensieFacade aardKodeExtensieFacade;

    public BerekenTheoretischJaarWedde(ConstantManager constantManager, NlpGlobalService service) {
        this.constantManager = constantManager;
        this.aardKodeExtensieFacade = service.getAardKodeExtensieFacade();
    }

    public BerekenTheoretischJaarWedde(ConstantManager constantManager, AardKodeExtensieFacade aardKodeExtensieFacade) {
        this.constantManager = constantManager;
        this.aardKodeExtensieFacade = aardKodeExtensieFacade;
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            if (rekenTijd.isAchterstal) {
                Money belastbaarAchterstal = berekenTheoretischJaarWedde(opdrachtContext, opdracht, true);
                opdrachtContext.put(BELASTBAAR_THEORETISCH_JAARWEDDE_ACHTERSTAL_KEY, belastbaarAchterstal);
                log.debug("opdrachtNr={},{}={}", opdracht.getOpdrachtnr(), BELASTBAAR_THEORETISCH_JAARWEDDE_ACHTERSTAL_KEY, belastbaarAchterstal);
            }
            Money belastbaar = berekenTheoretischJaarWedde(opdrachtContext, opdracht, false);
            opdrachtContext.put(BELASTBAAR_THEORETISCH_JAARWEDDE_KEY, belastbaar);
            log.debug("opdrachtNr={},{}={}", opdracht.getOpdrachtnr(), BELASTBAAR_THEORETISCH_JAARWEDDE_KEY, belastbaar);
        }
        return CONTINUE_PROCESSING;
    }

    private Money berekenTheoretischJaarWedde(RekenContext context, Opdracht huidigeOpdracht, boolean achterstal) {
        Integer fiscaalJaar = context.getInteger(FISCAAL_JAAR_KEY);
        RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);

        Opper huidigeNormOpper = context.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);

        PersoonsDataManager dataManager = context.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
        boolean bepaalOpEindeGerekendeOpdracht = false;
        if (achterstal) {
            Persoon opRekenDatum = dataManager.getPersoonOpDatum(rekenTijd.rekenDatum.dayOfMonth().withMaximumValue());
            bepaalOpEindeGerekendeOpdracht = opRekenDatum.getOpdrachten().isEmpty();
            huidigeNormOpper = dataManager.getOpperOpDatum(huidigeOpdracht, rekenTijd.rekenDatum);
        }
        GewWrkwBv huidigeFiscaleWerkwijze = huidigeNormOpper.getOpdrachtFiscaliteit().getWerkwijzeGewoneBezoldiging();

        LocalDate taxDatum = bepaalTaxDatum(huidigeNormOpper, rekenTijd, achterstal, bepaalOpEindeGerekendeOpdracht);
        RekenTijd selectieTijd = bepaalSelectieTijd(taxDatum, huidigeNormOpper, rekenTijd, bepaalOpEindeGerekendeOpdracht);

        RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager = context.getUnchecked(RKM_COREHR_CONFIG_MANAGER);
        RekenContext jaarContext = getJaarContext(huidigeNormOpper, dataManager, fiscaalJaar, selectieTijd, rekenTijd, regulManager, rkmCoreHrConfiguratieManager);
        Persoon persoon = jaarContext.getUnchecked(PERSOON_KEY);

        RekenChainFactory factory = context.getUnchecked(REKEN_CHAIN_FACTORY_KEY);
        Chain rekenChain = factory.getTheoretischBrutoEnBelastbaarChain(RkmTijdperk.getTijdperk(selectieTijd));
        try {
            rekenChain.execute(jaarContext);
        } catch (RuntimeException e) {
            throw e;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
        Money belastbaarTotaal = Money.ZERO;
        LoonElementManager manager = jaarContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        boolean bevatHuidigeOpdracht = persoon.getOpdrachten().stream().anyMatch(u -> u.getId().equals(huidigeOpdracht.getId()));
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            log.trace(LogTools.toSimpleLog(opdracht));
            RekenContext opdrachtContext = jaarContext.getOpdrachtContext(opdracht);
            Opper normOpper = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);
            GewWrkwBv fiscaleWerkwijze = normOpper.getOpdrachtFiscaliteit().getWerkwijzeGewoneBezoldiging();

            boolean maandbereik = true;
            if (fiscaalJaar < STARTJAAR_NIEUWE_REDENERING_THEORETISCH_BELASTBAAR) {
                maandbereik = normOpper.getActualInterval().contains(taxDatum);
            }

            if (!bevatHuidigeOpdracht || opdracht.getId().intValue() == huidigeOpdracht.getId() || (fiscaleWerkwijze == GewWrkwBv.BAREMA_KUMUL
                    && maandbereik && huidigeFiscaleWerkwijze == GewWrkwBv.BAREMA_KUMUL)) {
                Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
                log.trace("opdrachtsElementen:{}", loonElementen);
                Money belastbaar = getBelastbaar(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, rekenTijd.rekenDatum, loonElementen);
                log.trace("theoretischJaarWeddeOpdracht:{}", belastbaar);
                belastbaarTotaal = belastbaarTotaal.add(belastbaar);
            }
        }
        log.trace("theoretischJaarWedde:{}", belastbaarTotaal);
        return belastbaarTotaal;
    }

    private static Money getBelastbaar(RekenBvKey bvKey, LocalDate taxdatum, Collection<LoonElement> loonElementen) {
        LoonElementChecker checker = new CheckRegime(taxdatum, bvKey);
        return RekenTools.getSomProperty(BELASTBAAR_KEY, loonElementen, checker);
    }

    private static RekenTijd bepaalSelectieTijd(LocalDate taxDatum, Opper huidigeOpper, RekenTijd rekenTijd, boolean bepaalOpEindeGerekendeOpdracht) {
        LocalDateInterval selectiePeriode = new Month(taxDatum);
        LocalDate selectieDatum;
        if (!rekenTijd.isAchterstal) {
            selectieDatum = huidigeOpper.getActualTo().isBefore(selectiePeriode.getEnd()) ? huidigeOpper.getActualTo() : selectiePeriode.getEnd();
        } else {
            selectieDatum = rekenTijd.rekenDatum.dayOfMonth().withMaximumValue();
            if (bepaalOpEindeGerekendeOpdracht && huidigeOpper.getActualTo().isBefore(selectieDatum)) {
                selectieDatum = huidigeOpper.getActualTo();
            }
        }
        return new RekenTijd(selectiePeriode, selectieDatum, selectieDatum, rekenTijd.beslagDatum, rekenTijd.rekenTijdstip, rekenTijd.isAchterstal,
                rekenTijd.isApo);
    }

    private RekenContext getJaarContext(
            Opper huidigeNormOpper, PersoonsDataManager dataManager, Integer fiscaalJaar, RekenTijd selectieTijd,
            RekenTijd rekenTijd, RegulManager regulManager, RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager) {
        RekenContext mainContext = new RekenContext();
        mainContext.put(PERSOONSDATA_MANAGER_KEY, dataManager);
        RegulManager negerendeRegulManager = new RegulManagerImp();
        negerendeRegulManager.setIgnore(true);
        mainContext.put(REGUL_MANAGER_KEY, negerendeRegulManager);
        LoonCodeManager loonCodeManagerTmp = new LoonCodeManagerImp(negerendeRegulManager, aardKodeExtensieFacade);
        mainContext.put(LOONCODE_MANAGER_KEY, loonCodeManagerTmp);
        Persoon persoon = dataManager.getPersoonOpDatum(selectieTijd.rekenPeriode.getEnd(), true);
        if (persoon.getPersoonsFiscaliteitSlices().isEmpty()) {
            regulManager.doRegulException(null, Regulkode.PRSFISKALITEIT_NIET_GEVONDEN);
        }

        mainContext.put(PERSOON_KEY, persoon);
        mainContext.put(FISCAAL_JAAR_KEY, fiscaalJaar);
        mainContext.put(REKENTIJD_KEY, selectieTijd);
        mainContext.put(RKM_COREHR_CONFIG_MANAGER, rkmCoreHrConfiguratieManager);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            Opper normOpper = RekenTools.getOpperOpDatumOfLaatsteGegevens(opdracht, huidigeNormOpper.getActualTo());
            opdrachtContext.put(OPPER_LAATSTE_GEGEVENS_KEY, normOpper);
        }

        LocalDate zoekDatum = TimeTools.getZoekDatum(huidigeNormOpper, rekenTijd.rekenDatum, rekenTijd.rekenPeriode);

        Indexator indexator = new Indexator(constantManager, zoekDatum);
        mainContext.put(INDEXATOR_KEY, indexator);
        mainContext.put(THEORETISCHE_JAARWEDDE_MODUS_KEY, true);

        return mainContext;
    }

    private static LocalDate bepaalTaxDatum(Opper huidigeNormOpper, RekenTijd rekenTijd, boolean achterstal, boolean bepaalOpEindeGerekendeOpdracht) {
        LocalDate taxDatum;
        if (!achterstal) {
            taxDatum = huidigeNormOpper.getActualTo().isBefore(rekenTijd.eindDatum) ? huidigeNormOpper.getActualTo() : rekenTijd.eindDatum;
        } else {
            taxDatum = rekenTijd.rekenDatum.dayOfMonth().withMaximumValue();
            if (bepaalOpEindeGerekendeOpdracht && huidigeNormOpper.getActualTo().isBefore(taxDatum)) {
                taxDatum = huidigeNormOpper.getActualTo();
            }
        }
        return taxDatum;
    }
}
